# 基础栈的实现与括号匹配
class Stack:
    def __init__(self):
        self._items = []  # 使用列表作为底层存储

    def push(self, item):
        self._items.append(item)  # 入栈：添加到末尾

    def pop(self):
        if self.is_empty():
            raise IndexError("栈为空")
        return self._items.pop()  # 出栈：移除末尾元素

    def peek(self):
        if self.is_empty():
            raise IndexError("栈为空")
        return self._items[-1]  # 查看栈顶

    def is_empty(self):
        return len(self._items) == 0


def is_valid_brackets(s: str) -> bool:
    """判断括号字符串是否合法"""
    stack = Stack()
    pairs = {')': '(', ']': '[', '}': '{'}
    for ch in s:
        if ch in '([{':
            stack.push(ch)  # 左括号入栈
        elif ch in ')]}':
            if stack.is_empty() or stack.pop() != pairs[ch]:
                return False  # 栈空或括号不匹配
    return stack.is_empty()  # 最终栈必须为空


# 示例
print(is_valid_brackets("{[()]}"))   # True
print(is_valid_brackets("{[(]}"))    # False
